const runId = `${Date.now()}`;

return [{
  runId,
  generatedAt: new Date().toISOString(),
  threshold: 80,
  search: {
    roles: ['Senior QA Engineer', 'SDET', 'QA Automation Engineer'],
    requiredSkills: ['Selenium', 'Java', 'API Testing', 'JMeter'],
    preferredSkills: ['Rest Assured', 'TestNG', 'Jenkins', 'SQL'],
    locations: ['Remote', 'Bangalore', 'Hyderabad', 'Chennai', 'Pune'],
    excludeWords: ['intern', 'manual', 'support']
  },
  dataSources: {
    // Replace with real sources in your environment
    jobApiUrl: 'https://example.com/jobs',
    appliedJobsCsvPath: 'output/AppliedJobs.csv'
  },
  profileSource: 'config/profile.json',
  preferencesSource: 'config/preferences.json'
}];

// Placeholder job discovery node.
// Replace this node with HTTP Request nodes for LinkedIn/Naukri/Indeed APIs or your own scraper service.
const ctx = $json;

const mockJobs = [
  {
    company: 'Contoso Tech',
    role: 'Senior SDET',
    location: 'Remote',
    workMode: 'Remote',
    url: 'https://example.com/job/1',
    jd: 'Need Selenium, Java, API Testing, JMeter, CI/CD, Agile.',
    source: 'MockSource',
    postedDate: '2026-07-18'
  },
  {
    company: 'Fabrikam Systems',
    role: 'Manual QA Engineer',
    location: 'Bangalore',
    workMode: 'Hybrid',
    url: 'https://example.com/job/2',
    jd: 'Manual testing, support coordination, ticket handling.',
    source: 'MockSource',
    postedDate: '2026-07-18'
  },
  {
    company: 'Northwind Labs',
    role: 'QA Automation Engineer',
    location: 'Hyderabad',
    workMode: 'Hybrid',
    url: 'https://example.com/job/3',
    jd: 'Selenium, Java, Rest Assured, API automation, Jenkins, SQL.',
    source: 'MockSource',
    postedDate: '2026-07-17'
  }
];

return mockJobs.map((job) => ({
  ...ctx,
  job
}));

// Exclude intern/manual/support-like roles and keep target locations.
const { job, search } = $json;
const text = `${job.role} ${job.jd}`.toLowerCase();

const excluded = search.excludeWords.some((w) => text.includes(w));
const locationAllowed = search.locations.map((x) => x.toLowerCase()).includes(job.location.toLowerCase()) || job.workMode.toLowerCase() === 'remote';

if (excluded || !locationAllowed) {
  return [];
}

return [{ ...$json }];

// Placeholder duplicate check.
// Replace this with Data Store, SQLite, or CSV lookup against output/AppliedJobs.csv.
const key = `${$json.job.company}::${$json.job.role}::${$json.job.location}`.toLowerCase();

// Mock previously applied keys
const applied = [
  'sampleco::qa engineer::pune'
];

if (applied.includes(key)) {
  return [];
}

return [{ ...$json, dedupeKey: key }];

// Local scoring logic.
// Replace with OpenAI scoring node if needed.
const required = $json.search.requiredSkills;
const preferred = $json.search.preferredSkills;
const jd = $json.job.jd.toLowerCase();

let score = 0;
let matches = [];
let gaps = [];

for (const skill of required) {
  if (jd.includes(skill.toLowerCase())) {
    score += 18;
    matches.push(skill);
  } else {
    gaps.push(skill);
  }
}

for (const skill of preferred) {
  if (jd.includes(skill.toLowerCase())) {
    score += 4;
    matches.push(skill);
  }
}

if ($json.job.workMode.toLowerCase() === 'remote') score += 5;
if (score > 100) score = 100;

const decision = score >= $json.threshold ? 'Apply' : 'Skip';

return [{
  ...$json,
  matchScore: score,
  decision,
  scoreSummary: { matches, gaps }
}];

// Build prompt payloads for resume and cover letter generation.
// In production, send these to OpenAI/LLM nodes.
const promptBase = {
  role: $json.job.role,
  company: $json.job.company,
  location: $json.job.location,
  jd: $json.job.jd,
  score: $json.matchScore
};

const resumePrompt = [
  'Optimize resume for ATS without inventing skills.',
  `Role: ${promptBase.role}`,
  `Company: ${promptBase.company}`,
  `JD: ${promptBase.jd}`
].join('\n');

const coverLetterPrompt = [
  'Generate a concise 220-320 word cover letter with factual claims only.',
  `Role: ${promptBase.role}`,
  `Company: ${promptBase.company}`,
  `JD: ${promptBase.jd}`
].join('\n');

return [{
  ...$json,
  prompts: { resumePrompt, coverLetterPrompt }
}];

// Placeholder generated assets.
// Replace with LLM nodes and save output files by role/company.
const companySafe = $json.job.company.replace(/\s+/g, '_');
const roleSafe = $json.job.role.replace(/\s+/g, '_');

return [{
  ...$json,
  tailoredResumePath: `output/resume_${companySafe}_${roleSafe}.md`,
  coverLetterPath: `output/cover_${companySafe}_${roleSafe}.md`,
  applicationStatus: 'ReadyToApply'
}];

// Optional auto-apply integration point.
// Replace with HTTP Request to your Playwright microservice, or keep manual.

return [{
  ...$json,
  applicationStatus: 'Applied',
  applicationMode: 'ManualOrService',
  appliedAt: new Date().toISOString()
}];

// Create interview prep prompt after successful application.
const interviewPrompt = [
  'Generate interview prep for this role.',
  `Company: ${$json.job.company}`,
  `Role: ${$json.job.role}`,
  `JD: ${$json.job.jd}`,
  `MatchScore: ${$json.matchScore}`
].join('\n');

return [{
  ...$json,
  interviewPrompt
}];
